import type { ComponentProps } from "react";
import { useCallback, useEffect, type ReactElement } from "react";
import type { InputProps, RaRecord } from "ra-core";
import {
  FieldTitle,
  useChoices,
  useChoicesContext,
  useGetRecordRepresentation,
  useInput,
  useTranslate,
  type ChoicesProps,
} from "ra-core";
import { X } from "lucide-react";

import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { sanitizeInputRestProps } from "@/lib/sanitizeInputRestProps";
import { Skeleton } from "@/components/ui/skeleton";
import { cn } from "@/lib/utils";
import type { SupportCreateSuggestionOptions } from "@/hooks/useSupportCreateSuggestion";
import { useSupportCreateSuggestion } from "@/hooks/useSupportCreateSuggestion";
import { FormField, FormLabel, FormError, FormControl } from "@/components/ra-wrappers/form";
import { InputHelperText } from "@/components/ra-wrappers/input-helper-text";

export const SelectInput = (props: SelectInputProps) => {
  const {
    choices: choicesProp,
    isLoading: isLoadingProp,
    isFetching: isFetchingProp,
    isPending: isPendingProp,
    resource: resourceProp,
    source: sourceProp,

    optionText,
    optionValue,
    disableValue = "disabled",
    translateChoice,
    createValue,
    createHintValue,

    alwaysOn,
    defaultValue,
    format,
    label,
    helperText,
    name,
    onBlur,
    onChange,
    parse,
    validate,
    readOnly,
    disabled,

    className,
    emptyText = "",
    emptyValue = "",
    filter: _filter,
    create,
    createLabel,
    onCreate,

    ...rest
  } = props;
  const translate = useTranslate();

  useEffect(() => {
    if (emptyValue == null) {
      throw new Error(
        `emptyValue being set to null or undefined is not supported. Use parse to turn the empty string into null.`
      );
    }
  }, [emptyValue]);

  const {
    allChoices,
    isPending,
    error: fetchError,
    source,
    resource,
    isFromReference,
  } = useChoicesContext({
    choices: choicesProp,
    isLoading: isLoadingProp,
    isFetching: isFetchingProp,
    isPending: isPendingProp,
    resource: resourceProp,
    source: sourceProp,
  });

  if (source === undefined) {
    throw new Error(
      `If you're not wrapping the SelectInput inside a ReferenceInput, you must provide the source prop`
    );
  }

  if (!isPending && !fetchError && allChoices === undefined) {
    throw new Error(
      `If you're not wrapping the SelectInput inside a ReferenceInput, you must provide the choices prop`
    );
  }

  const getRecordRepresentation = useGetRecordRepresentation(resource);
  const { getChoiceText, getChoiceValue, getDisableValue } = useChoices({
    optionText: optionText ?? (isFromReference ? getRecordRepresentation : undefined),
    optionValue,
    disableValue,
    translateChoice: translateChoice ?? !isFromReference,
    createValue,
    createHintValue,
  });
  const { id, field, isRequired } = useInput({
    alwaysOn,
    defaultValue,
    format,
    label,
    helperText,
    name,
    onBlur,
    onChange,
    parse,
    resource,
    source,
    validate,
    readOnly,
    disabled,
  });

  const renderEmptyItemOption = useCallback(() => {
    return typeof emptyText === "string"
      ? emptyText === ""
        ? " " // em space, forces the display of an empty line of normal height
        : translate(emptyText, { _: emptyText })
      : emptyText;
  }, [emptyText, translate]);

  const renderMenuItemOption = useCallback(
    (choice: RaRecord) => getChoiceText(choice),
    [getChoiceText]
  );

  const handleChange = useCallback(
    (value: string) => {
      if (value === emptyValue) {
        field.onChange(emptyValue);
      } else {
        // Find the choice by value and pass it to field.onChange
        const choice = allChoices?.find((choice) => getChoiceValue(choice) === value);
        field.onChange(choice ? getChoiceValue(choice) : value);
      }
    },
    [field, getChoiceValue, emptyValue, allChoices]
  );

  const {
    getCreateItem,
    handleChange: handleChangeWithCreateSupport,
    createElement,
  } = useSupportCreateSuggestion({
    create,
    createLabel,
    createValue,
    createHintValue,
    onCreate,
    handleChange,
    optionText,
  });

  if (isPending) {
    return (
      <FormField id={id} name={field.name} className={cn("w-full min-w-20", className)}>
        {label !== "" && label !== false && (
          <FormLabel>
            <FieldTitle
              label={label}
              source={source}
              resource={resourceProp}
              isRequired={isRequired}
            />
          </FormLabel>
        )}
        <div className="relative">
          <Skeleton className="w-full h-11" />
        </div>
        <InputHelperText helperText={helperText} />
        <FormError />
      </FormField>
    );
  }

  const createItem = create || onCreate ? getCreateItem() : null;
  let finalChoices = fetchError ? [] : allChoices;
  if (create || onCreate) {
    finalChoices = [...finalChoices, createItem];
  }

  // Find the selected choice to display in the closed dropdown
  // This fixes a race condition where field.value is set before ReferenceInput loads choices.
  // Radix SelectValue only shows text when it finds a matching SelectItem in children.
  // Without this, the dropdown appears blank during the loading gap.
  const selectedChoice = finalChoices?.find(
    (choice) => choice && getChoiceValue(choice)?.toString() === field.value?.toString()
  );

  // Handle reset functionality
  const handleReset = (e: React.MouseEvent | React.KeyboardEvent) => {
    e.stopPropagation();
    field.onChange(emptyValue);
  };

  return (
    <>
      <FormField
        id={id}
        name={field.name}
        className={cn("w-full min-w-20", className)}
        {...sanitizeInputRestProps(rest)}
      >
        {label !== "" && label !== false && (
          <FormLabel>
            <FieldTitle
              label={label}
              source={source}
              resource={resourceProp}
              isRequired={isRequired}
            />
          </FormLabel>
        )}
        <FormControl>
          <div className="relative">
            <Select
              //FIXME https://github.com/radix-ui/primitives/issues/3135
              // Setting a key based on the value fixes an issue where onValueChange
              // was called with an empty string when the controlled value was changed.
              // See: https://github.com/radix-ui/primitives/issues/3135#issuecomment-2916908248
              key={`select:${field.value?.toString() ?? emptyValue}`}
              value={field.value?.toString() || emptyValue}
              onValueChange={handleChangeWithCreateSupport}
            >
              <SelectTrigger className={cn("w-full transition-all hover:bg-accent")}>
                <SelectValue placeholder={renderEmptyItemOption()}>
                  {selectedChoice ? (
                    renderMenuItemOption(selectedChoice)
                  ) : isFromReference && field.value && field.value !== emptyValue ? (
                    // Only show "Loading..." for ReferenceInput (async) scenarios,
                    // not when choices are provided directly (sync)
                    <span className="text-muted-foreground animate-pulse">Loading...</span>
                  ) : null}
                </SelectValue>

                {!isRequired && field.value && field.value !== emptyValue ? (
                  <div
                    role="button"
                    aria-label="Clear selection"
                    className="p-0 ml-auto pointer-events-auto hover:bg-transparent text-foreground/70 opacity-50 hover:opacity-100"
                    onClick={handleReset}
                    onKeyDown={(e) => {
                      if (e.key === "Enter" || e.key === " ") {
                        e.preventDefault();
                        handleReset(e);
                      }
                    }}
                    tabIndex={0}
                  >
                    <X className="h-4 w-4" />
                  </div>
                ) : null}
              </SelectTrigger>
              <SelectContent>
                {finalChoices?.map((choice) => {
                  if (!choice) return null;
                  const value = getChoiceValue(choice);
                  const isDisabled = getDisableValue(choice);

                  return (
                    <SelectItem key={value} value={value?.toString()} disabled={isDisabled}>
                      {renderMenuItemOption(
                        !!createItem && choice?.id === createItem.id ? createItem : choice
                      )}
                    </SelectItem>
                  );
                })}
              </SelectContent>
            </Select>
          </div>
        </FormControl>
        <InputHelperText helperText={helperText} />
        <FormError />
      </FormField>
      {createElement}
    </>
  );
};

export type SelectInputProps = ChoicesProps &
  // Source is optional as SelectInput can be used inside a ReferenceInput that already defines the source
  Partial<InputProps> &
  Omit<SupportCreateSuggestionOptions, "handleChange"> & {
    emptyText?: string | ReactElement;

    emptyValue?: string | number;
    onChange?: (value: string) => void;
  } & Omit<ComponentProps<typeof FormField>, "id" | "name" | "children">;
